module gray_code_counter (
    input clk,
    input reset,
    output reg [1:0] gray
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            gray <= 2'b00;
        else begin
            case (gray)
                2'b00: gray <= 2'b01;
                2'b01: gray <= 2'b11;
                2'b11: gray <= 2'b10;
                2'b10: gray <= 2'b00;
                default: gray <= 2'b00;
            endcase
        end
    end

  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        gray <= 2'b11;
      end else begin
        gray <= 2'b00;
      end;
    end
  end

endmodule

